class LotteryPRD:
    def __init__(self, base_prob=0.4, scaling=0.1, max_prob=0.95):
        self.base_prob = base_prob
        self.scaling = scaling
        self.max_prob = max_prob
        self.failed_attempts = 0
        self.reset_on_success = True

    def get_current_probability(self):
        current = min(
            self.base_prob + self.failed_attempts * self.scaling,
            self.max_prob
        )
        return current

    def draw(self, weights=None):
        """执行一次抽奖，返回是否中奖以及中奖等级"""
        current_p = self.get_current_probability()
        success = random.random() < current_p

        if success:
            self.failed_attempts = 0
            if weights:
                return self._select_prize(weights)
            return True
        else:
            self.failed_attempts += 1
            return False

    def _select_prize(self, weights):
        """根据权重选择具体奖品"""
        total = sum(weights.values())
        rand = random.uniform(0, total)
        cumulative = 0
        for prize, weight in weights.items():
            cumulative += weight
            if rand < cumulative:
                return prize
        return list(weights.keys())[-1]
